$c=Canvas 2200 1500; $g=$c.g; Title $g '09' 'Sequence telemetry qua TCP' 'Hai sender gửi telemetry; receiver cập nhật state rồi đại diện publish lên cloud.'; Lane $g 100 180 460 1180 'Sender A'; Lane $g 600 180 460 1180 'Sender B'; Lane $g 1100 180 460 1180 'Receiver'; Lane $g 1600 180 460 1180 'CoreIoT'; Panel $g 140 260 380 110 'Sender A chuẩn bị dữ liệu' @('updateSimulatedEnvironment()','runAiInference()') $theme.lgreen $theme.green; Panel $g 640 380 380 110 'Sender B chuẩn bị dữ liệu' @('updateSimulatedEnvironment()','runAiInference()') $theme.lgreen $theme.green; Arrow $g 330 560 1330 560 $theme.blue; Badge $g 830 520 'telemetry JSON'; Arrow $g 830 700 1330 700 $theme.blue; Badge $g 1080 660 'telemetry JSON'; Panel $g 1140 820 380 130 'Receiver xử lý packet' @('parseTelemetry()','applyTelemetry()','đánh dấu sender online') $theme.lblue $theme.blue; Arrow $g 1330 1070 1830 1070 $theme.orange; Badge $g 1580 1030 'publish gateway/telemetry'; Panel $g 1640 1160 360 110 'Dashboard cập nhật' @('timeline và widget nhận dữ liệu mới') $theme.lorange $theme.orange; Save $c '09_seq_tcp_telemetry.png'
$c=Canvas 2200 1500; $g=$c.g; Title $g '10' 'Sequence đổi threshold' 'Receiver tạo gói config, sender áp dụng giá trị mới rồi gửi ACK xác nhận.'; Lane $g 100 180 460 1180 'Receiver UI'; Lane $g 600 180 460 1180 'Receiver'; Lane $g 1100 180 460 1180 'Sender'; Lane $g 1600 180 460 1180 'CoreIoT'; Arrow $g 330 360 830 360 $theme.blue; Badge $g 580 320 'set threshold từ web UI'; Panel $g 640 470 380 110 'Receiver tạo pendingConfig' @('Tăng configVersion','Ghi desiredThreshold') $theme.lblue $theme.blue; Arrow $g 830 700 1330 700 $theme.red; Badge $g 1080 660 'config JSON'; Panel $g 1140 800 380 110 'Sender áp dụng cấu hình' @('Lưu file config','Cập nhật threshold') $theme.lgreen $theme.green; Arrow $g 1330 1010 830 1010 $theme.green; Badge $g 1080 970 'config_ack'; Arrow $g 830 1170 1830 1170 $theme.orange 'Dash'; Badge $g 1330 1130 'attribute threshold mới'; Save $c '10_seq_rpc_threshold.png'
$c=Canvas 2200 1500; $g=$c.g; Title $g '12' 'Sequence receiver làm MQTT gateway' 'Receiver đại diện cho sender khi kết nối cloud, publish dữ liệu và xử lý RPC.'; Lane $g 100 180 460 1180 'Sender'; Lane $g 600 180 460 1180 'Receiver'; Lane $g 1100 180 460 1180 'MQTT broker'; Lane $g 1600 180 460 1180 'CoreIoT'; Arrow $g 330 360 830 360 $theme.blue; Badge $g 580 320 'telemetry JSON'; Panel $g 640 470 380 110 'Receiver gom dữ liệu' @('gắn device_id','chọn topic gateway phù hợp') $theme.lblue $theme.blue; Arrow $g 830 700 1330 700 $theme.orange; Badge $g 1080 660 'v1/gateway/connect / telemetry'; Arrow $g 1330 860 1830 860 $theme.orange; Badge $g 1580 820 'CoreIoT nhận dữ liệu'; Arrow $g 1830 1020 1330 1020 $theme.red 'Dash'; Badge $g 1580 980 'RPC setThreshold'; Arrow $g 1330 1160 830 1160 $theme.red 'Dash'; Badge $g 1080 1120 'gateway/rpc'; Save $c '12_seq_mqtt_gateway.png'
$c=Canvas 2200 1500; $g=$c.g; Title $g '19' 'Sequence end-to-end' 'Hình tổng hợp luồng dữ liệu đi lên, điều khiển đi xuống và cập nhật trình duyệt.'; Lane $g 100 180 460 1180 'Sender'; Lane $g 600 180 460 1180 'Receiver'; Lane $g 1100 180 460 1180 'CoreIoT'; Lane $g 1600 180 460 1180 'Browser'; Arrow $g 330 360 830 360 $theme.blue; Badge $g 580 320 'telemetry JSON'; Arrow $g 830 560 1330 560 $theme.orange; Badge $g 1080 520 'MQTT telemetry'; Arrow $g 1330 760 830 760 $theme.red 'Dash'; Badge $g 1080 720 'RPC setThreshold'; Arrow $g 830 960 330 960 $theme.red; Badge $g 580 920 'config JSON'; Arrow $g 330 1120 830 1120 $theme.green; Badge $g 580 1080 'config_ack'; Arrow $g 830 1260 1830 1260 $theme.purple; Badge $g 1330 1220 'WebSocket snapshot'; Save $c '19_seq_end_to_end.png'
$c=Canvas 2200 1500; $g=$c.g; Title $g '17' 'Bảng message TCP' 'Ba loại packet chính là telemetry, config và config_ack.'; TableDraw $g 90 190 @(260,420,620,700) @('Loại gói','Hướng truyền','Trường tiêu biểu','Ý nghĩa') @(@('telemetry','sender -> receiver','device_id, temperature, humidity, ai_score...','Gửi dữ liệu đo và kết quả TinyML'),@('config','receiver -> sender','device_id, threshold, receiver_ip...','Đồng bộ cấu hình xuống sender'),@('config_ack','sender -> receiver','device_id, config_version, applied_threshold','Xác nhận sender đã áp dụng cấu hình')); Save $c '17_bang_message_tcp.png'
$c=Canvas 2200 1500; $g=$c.g; Title $g '18' 'Bảng topic MQTT gateway' 'Receiver dùng nhóm topic gateway để đưa sender lên CoreIoT.'; TableDraw $g 120 190 @(420,700,900) @('Topic','Loại dữ liệu','Vai trò') @(@('v1/gateway/connect','connect payload','Khai báo sender online với cloud'),@('v1/gateway/disconnect','disconnect payload','Thông báo sender offline'),@('v1/gateway/telemetry','telemetry payload','Đẩy dữ liệu đo lên dashboard'),@('v1/gateway/attributes','attributes payload','Cập nhật threshold và metadata'),@('v1/gateway/rpc','RPC request/response','Nhận lệnh điều khiển từ cloud')); Save $c '18_bang_mqtt_topics.png'
$c=Canvas; $g=$c.g; Title $g '19' 'Mô hình dữ liệu trung tâm của receiver' 'Tất cả quyết định của receiver đều xoay quanh SenderState và registry thiết bị.'; Panel $g 120 300 400 320 'GatewayConfig' @('Wi-Fi','MQTT token','cổng TCP','trạng thái cloud') $theme.lblue $theme.blue; Panel $g 620 220 460 480 'SenderState' @('deviceId, name','online, hasTelemetry','temperature, humidity','desiredThreshold','reportedThreshold','pendingConfig, awaitingAck','aiScore, aiAnomaly') $theme.lgreen $theme.green; Panel $g 1180 300 400 320 'UnknownDevice' @('deviceId','lastSeen','telemetry gần nhất') $theme.lorange $theme.orange; Panel $g 1680 300 400 320 'ConnectionPool' @('socket đang mở','dòng dữ liệu đệm','thời điểm hoạt động') $theme.lred $theme.red; Arrow $g 520 460 620 460 $theme.border; Arrow $g 1080 460 1180 460 $theme.border; Arrow $g 1580 460 1680 460 $theme.border; Save $c '19_receiver_data_model.png'
